class Solution {
    public int largestInteger(int num) {
        String numStr = String.valueOf(num);
        char[] chars = numStr.toCharArray();
        int n = chars.length;

        // Separate odd and even digits
        char[] odd = new char[n];
        char[] even = new char[n];
        int oddIndex = 0, evenIndex = 0;

        for (char c : chars) {
            if ((c - '0') % 2 == 0) {
                even[evenIndex++] = c;
            } else {
                odd[oddIndex++] = c;
            }
        }

        // Sort odd and even digits in descending order
        odd = Arrays.copyOf(odd, oddIndex);
        even = Arrays.copyOf(even, evenIndex);
        Arrays.sort(odd);
        Arrays.sort(even);

        // Reconstruct the number with largest possible value
        int oddPtr = oddIndex - 1;
        int evenPtr = evenIndex - 1;
        for (int i = 0; i < n; i++) {
            if ((chars[i] - '0') % 2 == 0) {
                chars[i] = even[evenPtr--];
            } else {
                chars[i] = odd[oddPtr--];
            }
        }

        return Integer.parseInt(new String(chars));
    }
}
